Rules.InvariantScript:
ForAll(galStakeholderSAS.AllItems,
  Patch(CRStakeholderReviews,
    LookUp(CRStakeholderReviews,
      CRNumber.CRNumber = gblDetailCR.CRNumber And StakeholderGroup.Value = ThisRecord.StakeholderGroup.Value),
    {
      RAGStatus: {Value: ThisRecord.ddlRAGSAS.Selected.Value},
      ImpactStatement: ThisRecord.txtImpactSAS.Text,
      Reviewer: {Claims: "i:0#.f|membership|" & User().Email, DisplayName: User().FullName, Department: ""},
      ReviewDate: Today(),
      IsComplete: Not(ThisRecord.ddlRAGSAS.Selected.Value = "Pale Blue") And Not(IsBlank(ThisRecord.txtImpactSAS.Text))
    }
  )
);
If(IsEmpty(Errors(CRStakeholderReviews)),
  Notify("Stakeholder reviews saved.", NotificationType.Success),
  Notify("Save failed — " & First(Errors(CRStakeholderReviews)).Message, NotificationType.Error)
)
